/**
 * @module ForecastService
 * @description Provides business logic for calculating billing forecasts.
 */

import { Subscription } from '../billing';

export interface MonthlyForecast {
  month: string; // e.g., "YYYY-MM"
  projectedMRR: number; // Projected Monthly Recurring Revenue
}

/**
 * Calculates a 3-month billing forecast based on current subscriptions and a historical growth rate.
 * @param currentSubscriptions An array of current active subscriptions.
 * @param historicalGrowthRate The historical monthly growth rate (e.g., 0.03 for 3%).
 * @returns An array of MonthlyForecast objects for the next 3 months.
 */
export function calculateBillingForecast(
  currentSubscriptions: Subscription[],
  historicalGrowthRate: number
): MonthlyForecast[] {
  if (historicalGrowthRate < 0) {
    console.warn('Historical growth rate is negative. This might indicate a shrinking business.');
  }

  // Calculate current Monthly Recurring Revenue (MRR)
  const currentMRR = currentSubscriptions.reduce((sum, sub) => sum + sub.monthlyPrice, 0);

  const forecast: MonthlyForecast[] = [];
  let projectedMRR = currentMRR;

  // Project for the next 3 months
  for (let i = 1; i <= 3; i++) {
    projectedMRR *= (1 + historicalGrowthRate); // Apply growth rate
    const date = new Date();
    date.setMonth(date.getMonth() + i); // Get the month for the forecast

    forecast.push({
      month: `${date.getFullYear()}-${(date.getMonth() + 1).toString().padStart(2, '0')}`,
      projectedMRR: parseFloat(projectedMRR.toFixed(2)), // Round to 2 decimal places
    });
  }

  return forecast;
}
