 * @description Main application entry point. Sets up the Hono server and registers routes.
 */

import { Hono } from 'hono';
import forecastRouter from './modules/forecast/route';

// Create a new Hono application instance
const app = new Hono();

// Register the forecast router under the '/forecast' base path
app.route('/forecast', forecastRouter);

// Define a simple root route for health check or basic info
app.get('/', (c) => {
  return c.json({ message: 'Welcome to the Billing Forecast API! Try /forecast/billing' });
});

// Export the Hono app instance.
// This is typically used by a server entry point (e.g., `server.ts` or `index.js` for Node.js)
// or by a serverless function handler.
export default app;

// Example of how to run the app locally (for development/testing)
// In a real Node.js project, you might use `app.listen()` or integrate with a specific adapter.
// For Hono, you'd typically use a server adapter like `@hono/node-server`.
// This block is for demonstration and won't be part of the final build if using a framework adapter.
if (process.env.NODE_ENV !== 'production') {
  import('@hono/node-server').then(({ serve }) => {
    serve({
      fetch: app.fetch,
      port: 3000,
    }, (info) => {
      console.log(`Server listening on http://localhost:${info.port}`);
      console.log('Try: http://localhost:3000/forecast/billing');
    });
  }).catch(err => {
    console.error('Failed to start server:', err);
  });
}
